            transform: none;
        }

        /* ── Array display ── */
        .array-wrapper {
            overflow-x: auto;
            padding: 10px 0 20px;
        }

        .array-container {
            display: flex;
            gap: 8px;
            justify-content: center;
            flex-wrap: wrap;
            min-height: 110px;
