            padding: 10px;
        }

        .box-wrapper {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 6px;
        }

        .box {
            width: 56px;
            height: 56px;
            border-radius: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.1rem;
            font-weight: 700;
            color: #fff;
            border: 2px solid transparent;
            background: rgba(255, 255, 255, 0.08);
            transition: all 0.4s ease;
            position: relative;
        }

        .box-index {
            font-size: 0.7rem;
            color: #7777aa;
            font-weight: 500;
        }

        /* State classes */
        .box.in-range {
            background: rgba(255, 255, 255, 0.12);
            border-color: rgba(0, 180, 216, 0.5);
            color: #c0e8ff;
        }

        .box.out-of-range {
            background: rgba(0, 0, 0, 0.25);
            border-color: transparent;
            color: #444466;
            transform: scale(0.88);
        }

        .box.mid {
            background: linear-gradient(135deg, #f9a825, #f57f17);
            border-color: #ffd54f;
            color: #fff;
            transform: scale(1.18);
            box-shadow: 0 0 20px rgba(249, 168, 37, 0.7);
            z-index: 2;
        }

        .box.found {
            background: linear-gradient(135deg, #00e676, #00c853);
            border-color: #69f0ae;
            color: #fff;
            transform: scale(1.25);
            box-shadow: 0 0 28px rgba(0, 230, 118, 0.8);
            z-index: 3;
            animation: pulse-found 0.8s ease infinite alternate;
        }

        .box.eliminated {
            background: rgba(0, 0, 0, 0.3);
            border-color: transparent;
            color: #333355;
            transform: scale(0.85);
        }

        @keyframes pulse-found {
            from { box-shadow: 0 0 20px rgba(0, 230, 118, 0.6); }
            to   { box-shadow: 0 0 40px rgba(0, 230, 118, 1.0); }
        }

        /* Pointer labels */
        .pointer-label {
            font-size: 0.65rem;
            font-weight: 700;
            padding: 2px 5px;
            border-radius: 4px;
            letter-spacing: 0.5px;
            min-height: 18px;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 3px;
        }

        .ptr-low  { color: #80cbc4; }
        .ptr-high { color: #ef9a9a; }
        .ptr-mid  { color: #ffd54f; }

        /* ── Info panel ── */
        .info-panel {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
            gap: 12px;
            margin: 20px 0;
        }

        .info-card {
            background: rgba(255,255,255,0.06);
            border: 1px solid rgba(255,255,255,0.1);
            border-radius: 12px;
            padding: 14px;
            text-align: center;
        }

        .info-card .label {
            font-size: 0.72rem;
            color: #8888aa;
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 6px;
        }

        .info-card .value {
            font-size: 1.4rem;
            font-weight: 700;
            color: #e0e0ff;
        }

        /* ── Status message ── */
        .status-message {
            text-align: center;
            font-size: 1.1rem;
            font-weight: 600;
            padding: 14px 20px;
            border-radius: 12px;
            margin: 16px 0;
            min-height: 52px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.4s;
        }

        .status-message.idle {
            background: rgba(255,255,255,0.04);
            color: #7777aa;
            border: 1px dashed rgba(255,255,255,0.1);
        }

        .status-message.searching {
            background: rgba(0, 180, 216, 0.12);
            color: #80d8ff;
            border: 1px solid rgba(0, 180, 216, 0.3);
        }

        .status-message.found-msg {
            background: rgba(0, 230, 118, 0.12);
            color: #69f0ae;
            border: 1px solid rgba(0, 230, 118, 0.4);
        }

        .status-message.not-found-msg {
            background: rgba(247, 37, 133, 0.12);
            color: #ff80ab;
            border: 1px solid rgba(247, 37, 133, 0.4);
        }

        /* ── Steps log ── */
        .steps-log {
            background: rgba(0,0,0,0.25);
            border: 1px solid rgba(255,255,255,0.08);
            border-radius: 12px;
            padding: 16px;
            max-height: 200px;
            overflow-y: auto;
            margin-top: 16px;
        }

        .steps-log h3 {
            color: #8888aa;
            font-size: 0.8rem;
            text-transform: uppercase;
            letter-spacing: 1px;
            margin-bottom: 10px;
        }

        .log-entry {
            display: flex;
            align-items: flex-start;
            gap: 10px;
            padding: 6px 0;
            border-bottom: 1px solid rgba(255,255,255,0.05);
            font-size: 0.85rem;
            color: #b0b0cc;
            animation: slideIn 0.3s ease;
        }

        .log-entry:last-child { border-bottom: none; }

        .log-entry .step-num {
            background: rgba(123, 104, 238, 0.3);
            color: #b39ddb;
            font-size: 0.7rem;
            font-weight: 700;
            padding: 2px 7px;
            border-radius: 20px;
            white-space: nowrap;
            margin-top: 1px;
        }

        @keyframes slideIn {
            from { opacity: 0; transform: translateX(-10px); }
            to   { opacity: 1; transform: translateX(0); }
        }

        /* ── Legend ── */
        .legend {
            display: flex;
            flex-wrap: wrap;
            gap: 14px;
            justify-content: center;
            margin-top: 18px;
        }

        .legend-item {
            display: flex;
            align-items: center;
            gap: 7px;
            font-size: 0.8rem;
            color: #9999bb;
        }

        .legend-dot {
            width: 14px;
            height: 14px;
            border-radius: 4px;
        }

        .dot-range    { background: rgba(0, 180, 216, 0.5); border: 1px solid #00b4d8; }
        .dot-mid      { background: linear-gradient(135deg, #f9a825, #f57f17); }
        .dot-found    { background: linear-gradient(135deg, #00e676, #00c853); }
        .dot-elim     { background: rgba(255,255,255,0.08); border: 1px solid #333; }

        /* Scrollbar */
        .steps-log::-webkit-scrollbar { width: 5px; }
        .steps-log::-webkit-scrollbar-track { background: transparent; }
        .steps-log::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 10px; }
    </style>
</head>
<body>
<div class="container">
    <h1>🔍 Binary Search</h1>
    <p class="subtitle">Step through the algorithm on a sorted array</p>

    <!-- Controls -->
    <div class="controls">
        <label for="targetInput">Target value:</label>
        <input type="number" id="targetInput" value="37" min="1" max="99" />
        <button class="btn-start" id="btnStart" onclick="startSearch()">▶ Start</button>
        <button class="btn-step"  id="btnStep"  onclick="stepSearch()" disabled>⏭ Step</button>
        <button class="btn-reset" id="btnReset" onclick="resetAll()">↺ Reset</button>
    </div>

    <!-- Status -->
    <div class="status-message idle" id="statusMsg">
        Enter a target and press <strong>&nbsp;▶ Start&nbsp;</strong> to begin.
    </div>

    <!-- Info cards -->
    <div class="info-panel">
        <div class="info-card">
            <div class="label">Low</div>
            <div class="value" id="infoLow">—</div>
        </div>
        <div class="info-card">
            <div class="label">High</div>
            <div class="value" id="infoHigh">—</div>
        </div>
        <div class="info-card">
            <div class="label">Mid</div>
            <div class="value" id="infoMid">—</div>
        </div>
        <div class="info-card">
            <div class="label">Mid Value</div>
            <div class="value" id="infoMidVal">—</div>
        </div>
        <div class="info-card">
            <div class="label">Step</div>
            <div class="value" id="infoStep">0</div>
        </div>
        <div class="info-card">
            <div class="label">Comparisons</div>
            <div class="value" id="infoComps">0</div>
        </div>
    </div>

    <!-- Array -->
    <div class="array-wrapper">
        <div class="array-container" id="arrayContainer"></div>
    </div>

    <!-- Legend -->
    <div class="legend">
        <div class="legend-item"><div class="legend-dot dot-range"></div> Active range</div>
        <div class="legend-item"><div class="legend-dot dot-mid"></div> Mid element</div>
        <div class="legend-item"><div class="legend-dot dot-found"></div> Found</div>
        <div class="legend-item"><div class="legend-dot dot-elim"></div> Eliminated</div>
    </div>

    <!-- Log -->
    <div class="steps-log">
        <h3>📋 Step Log</h3>
        <div id="logEntries"></div>
    </div>
</div>

<script>
    /* ── Data ── */
    const ARRAY = [2, 5, 8, 12, 16, 23, 29, 37, 43, 50, 56, 64, 71, 78, 85, 91];

    /* ── State ── */
    let low, high, mid, target, stepCount, comparisons;
    let searching = false;
    let done = false;

    /* ── Init ── */
    window.onload = () => {
        buildArray();
    };

    function buildArray() {
        const container = document.getElementById('arrayContainer');
        container.innerHTML = '';
        ARRAY.forEach((val, idx) => {
            const wrapper = document.createElement('div');
            wrapper.className = 'box-wrapper';

            const ptr = document.createElement('div');
            ptr.className = 'pointer-label';
            ptr.id = `ptr-${idx}`;

            const box = document.createElement('div');
            box.className = 'box';
            box.id = `box-${idx}`;
            box.textContent = val;

            const indexLabel = document.createElement('div');
            indexLabel.className = 'box-index';
            indexLabel.textContent = idx;

            wrapper.appendChild(ptr);
            wrapper.appendChild(box);
            wrapper.appendChild(indexLabel);
            container.appendChild(wrapper);
        });
    }

    /* ── Start ── */
    function startSearch() {
        const input = document.getElementById('targetInput').value.trim();
        target = parseInt(input, 10);

        if (isNaN(target)) {
            showStatus('⚠️ Please enter a valid number.', 'searching');
            return;
        }

        low  = 0;
        high = ARRAY.length - 1;
        mid  = null;
        stepCount   = 0;
        comparisons = 0;
        searching   = true;
        done        = false;

        document.getElementById('logEntries').innerHTML = '';
        document.getElementById('btnStart').disabled = true;
        document.getElementById('btnStep').disabled  = false;
        document.getElementById('targetInput').disabled = true;

        updateInfoCards();
        renderArray('init');
        showStatus(`🔎 Searching for <strong>&nbsp;${target}&nbsp;</strong> — press ⏭ Step to proceed.`, 'searching');
        addLog('Search started', `target = ${target}, array size = ${ARRAY.length}`);
    }

    /* ── Step ── */
    function stepSearch() {
        if (done || !searching) return;

        if (low > high) {
            finishNotFound();
            return;
        }

        stepCount++;
        comparisons++;
        mid = Math.floor((low + high) / 2);

        updateInfoCards();
        renderArray('step');

        const midVal = ARRAY[mid];

        if (midVal === target) {
            finishFound();
        } else if (midVal < target) {
            addLog(`Step ${stepCount}`, `mid=${mid} → arr[${mid}]=${midVal} < ${target} → move low to ${mid + 1}`);
            showStatus(`Step ${stepCount}: arr[${mid}] = ${midVal} < ${target} → search right half`, 'searching');
            low = mid + 1;
        } else {
            addLog(`Step ${stepCount}`, `mid=${mid} → arr[${mid}]=${midVal} > ${target} → move high to ${mid - 1}`);
            showStatus(`Step ${stepCount}: arr[${mid}] = ${midVal} > ${target} → search left half`, 'searching');
            high = mid - 1;
        }

        updateInfoCards();

        if (low > high && !done) {
            /* Next step will call finishNotFound via the guard at top */
            /* But let's be proactive: disable step if we know it's over */
        }
    }

    /* ── Render array ── */
    function renderArray(phase) {
        ARRAY.forEach((_, idx) => {
            const box = document.getElementById(`box-${idx}`);
            const ptr = document.getElementById(`ptr-${idx}`);
            ptr.innerHTML = '';
            box.className = 'box';

            if (phase === 'init') {
                box.classList.add('in-range');
                return;
            }

            if (done && idx === mid) {
                const foundClass = (ARRAY[mid] === target) ? 'found' : 'eliminated';
                box.classList.add(foundClass);
                return;
            }

            if (idx < low || idx > high) {
                box.classList.add('eliminated');
            } else if (idx === mid) {
                box.classList.add('mid');
            } else {
                box.classList.add('in-range');
            }

            /* Pointer labels */
            const labels = [];
            if (idx === low  && idx === high && idx === mid) { labels.push('<span class="ptr-low">L</span><span class="ptr-mid">M</span><span class="ptr-high">H</span>'); }
            else {
                if (idx === low)  labels.push('<span class="ptr-low">L</span>');
                if (idx === mid)  labels.push('<span class="ptr-mid">M</span>');
                if (idx === high) labels.push('<span class="ptr-high">H</span>');
            }
            ptr.innerHTML = labels.join('');
        });
    }

    /* ── Finish found ── */
    function finishFound() {
        done = true;
        searching = false;
        renderArray('done');
        showStatus(`✅ Found <strong>&nbsp;${target}&nbsp;</strong> at index <strong>&nbsp;${mid}&nbsp;</strong> in ${stepCount} step${stepCount !== 1 ? 's' : ''}!`, 'found-msg');
        addLog(`✅ FOUND`, `target ${target} is at index ${mid} — total comparisons: ${comparisons}`);
        document.getElementById('btnStep').disabled = true;
        updateInfoCards();
    }

    /* ── Finish not found ── */
    function finishNotFound() {
        done = true;
        searching = false;
        /* Eliminate everything */
        ARRAY.forEach((_, idx) => {
            const box = document.getElementById(`box-${idx}`);
            document.getElementById(`ptr-${idx}`).innerHTML = '';
            box.className = 'box eliminated';
        });
        showStatus(`❌ <strong>&nbsp;${target}&nbsp;</strong> is not in the array. Search ended after ${stepCount} step${stepCount !== 1 ? 's' : ''}.`, 'not-found-msg');
        addLog(`❌ NOT FOUND`, `target ${target} not in array — total comparisons: ${comparisons}`);
        document.getElementById('btnStep').disabled = true;
        updateInfoCards();
    }

    /* ── Reset ── */
    function resetAll() {
        low = high = mid = null;
        stepCount = comparisons = 0;
        searching = done = false;
        target = null;

        document.getElementById('btnStart').disabled = false;
        document.getElementById('btnStep').disabled  = true;
        document.getElementById('targetInput').disabled = false;
        document.getElementById('logEntries').innerHTML = '';

        buildArray();
        updateInfoCards();
        showStatus('Enter a target and press <strong>&nbsp;▶ Start&nbsp;</strong> to begin.', 'idle');
    }

    /* ── Helpers ── */
    function showStatus(html, type) {
        const el = document.getElementById('statusMsg');
        el.innerHTML = html;
        el.className = `status-message ${type}`;
    }

    function updateInfoCards() {
        document.getElementById('infoLow').textContent    = (low  !== null && low  <= ARRAY.length - 1 && !done) ? low  : (done ? '—' : '—');
        document.getElementById('infoHigh').textContent   = (high !== null && high >= 0                && !done) ? high : (done ? '—' : '—');
        document.getElementById('infoMid').textContent    = mid  !== null ? mid  : '—';
        document.getElementById('infoMidVal').textContent = mid  !== null ? ARRAY[mid] : '—';
        document.getElementById('infoStep').textContent   = stepCount;
        document.getElementById('infoComps').textContent  = comparisons;

        /* Live update low/high even mid-search */
        if (searching && !done) {
            document.getElementById('infoLow').textContent  = low;
            document.getElementById('infoHigh').textContent = high;
        }
    }

    function addLog(title, detail) {
        const entries = document.getElementById('logEntries');
        const entry = document.createElement('div');
        entry.className = 'log-entry';
        entry.innerHTML = `<span class="step-num">${title}</span><span>${detail}</span>`;
        entries.appendChild(entry);
        entries.scrollTop = entries.scrollHeight;
    }
</script>
</body>
</html>
```

---

## What's included

| Feature | Details |
|---|---|
| **Array** | 16 pre-sorted values (2 → 91) |
| **Target input** | Type any integer; try values in *and* out of the array |
| **▶ Start** | Initializes state, highlights full range |
| **⏭ Step** | One iteration per click — updates Low / Mid / High pointers |
| **↺ Reset** | Clears everything back to the initial state |
| **Color coding** | 🔵 Active range · 🟠 Mid element · 🟢 Found · ⬛ Eliminated |
| **Info cards** | Live Low / High / Mid index, Mid value, step count, comparisons |
| **Step log** | Scrollable history of every decision made |
| **Pointer labels** | L / M / H labels float above each relevant box |

Just save it as **`binary-search.html`** and open it in any browser — no dependencies needed!

