      border-radius: 4px;
      border: 2px solid;
    }

    .ld-range  { border-color: #0ea5e9; background: #0c2a3e; }
    .ld-mid    { border-color: #f59e0b; background: #3b2200; }
    .ld-found  { border-color: #22c55e; background: #052e16; }
    .ld-out    { border-color: #2a2a3e; background: #1a1a2e; opacity: 0.35; }
  </style>
</head>
<body>

  <h1>🔍 Binary Search Visualizer</h1>
  <p class="subtitle">Watch the algorithm narrow down the search range step by step</p>

  <div class="controls">
    <input type="number" id="targetInput" placeholder="Target value" />
    <button id="startBtn" onclick="startSearch()">Search</button>
    <button id="stepBtn" onclick="step()" disabled>Step ▶</button>
    <button id="resetBtn" onclick="resetAll()">Reset</button>
  </div>

  <div class="array-wrapper">
    <div class="pointer-row" id="pointerRow"></div>
    <div class="array-container" id="arrayContainer"></div>
  </div>

  <div class="result-banner" id="resultBanner"></div>

  <div class="info-panel" id="infoPanel">
    <div class="step-label">Status</div>
    <div class="message" id="infoMessage">Enter a target value and press Search to begin.</div>
    <div class="vars" id="infoVars"></div>
  </div>

  <div class="legend">
    <div class="legend-item"><div class="legend-dot ld-range"></div> In search range</div>
    <div class="legend-item"><div class="legend-dot ld-mid"></div> Middle element</div>
    <div class="legend-item"><div class="legend-dot ld-found"></div> Found!</div>
    <div class="legend-item"><div class="legend-dot ld-out"></div> Eliminated</div>
  </div>

  <script>
    // ── Data ──────────────────────────────────────────────────────────────────
    const ARRAY = [3, 7, 11, 15, 19, 23, 28, 34, 41, 47, 53, 60, 68, 75, 82, 90];

    // ── State ─────────────────────────────────────────────────────────────────
    let lo, hi, mid, target, done, stepCount, foundIndex;

    // ── Init ──────────────────────────────────────────────────────────────────
    function init() {
      lo = 0;
      hi = ARRAY.length - 1;
      mid = null;
      done = false;
      stepCount = 0;
      foundIndex = -1;
    }

    // ── Render array boxes ────────────────────────────────────────────────────
    function renderArray(highlightFound = false) {
      const container = document.getElementById('arrayContainer');
      const pointerRow = document.getElementById('pointerRow');
      container.innerHTML = '';
      pointerRow.innerHTML = '';

      ARRAY.forEach((val, i) => {
        // Determine box state
        let cls = '';
        if (highlightFound && i === foundIndex) {
          cls = 'found';
        } else if (mid !== null && i === mid && !highlightFound) {
          cls = 'mid';
        } else if (mid !== null && i >= lo && i <= hi && !highlightFound) {
          cls = 'in-range';
        } else if (!highlightFound && mid !== null && (i < lo || i > hi)) {
          cls = 'out-of-range';
        } else if (highlightFound && i !== foundIndex) {
          cls = 'out-of-range';
        }

        // Box
        const box = document.createElement('div');
        box.className = `box ${cls}`;
        box.id = `box-${i}`;

        const idxLabel = document.createElement('span');
        idxLabel.className = 'index-label';
        idxLabel.textContent = i;

        box.appendChild(idxLabel);
        box.appendChild(document.createTextNode(val));
        container.appendChild(box);

        // Pointer cell
        const cell = document.createElement('div');
        cell.className = 'pointer-cell';

        const ptrs = [];
        if (mid !== null && i === lo)  ptrs.push({ label: 'LO',  cls: 'ptr-lo'  });
        if (mid !== null && i === hi)  ptrs.push({ label: 'HI',  cls: 'ptr-hi'  });
        if (mid !== null && i === mid) ptrs.push({ label: 'MID', cls: 'ptr-mid' });

        if (ptrs.length === 1) {
          cell.textContent = ptrs[0].label;
          cell.classList.add(ptrs[0].cls);
        } else if (ptrs.length > 1) {
          cell.textContent = ptrs.map(p => p.label).join('/');
          cell.classList.add('ptr-multi');
          cell.style.color = '#c084fc';
        }

        pointerRow.appendChild(cell);
      });
    }

    // ── Update info panel ─────────────────────────────────────────────────────
    function updateInfo(msg) {
      document.getElementById('infoMessage').textContent = msg;

      const varsEl = document.getElementById('infoVars');
      if (mid !== null) {
        varsEl.innerHTML = `
          <span class="var-lo">LO = ${lo}</span>
          <span class="var-mid">MID = ${mid}</span>
          <span class="var-hi">HI = ${hi}</span>
        `;
      } else {
        varsEl.innerHTML = '';
      }
    }

    // ── Start search ──────────────────────────────────────────────────────────
    function startSearch() {
      const raw = document.getElementById('targetInput').value.trim();
      if (raw === '') {
        alert('Please enter a target value.');
        return;
      }

      target = parseInt(raw, 10);
      if (isNaN(target)) {
        alert('Please enter a valid integer.');
        return;
      }

      // Hide result banner
      const banner = document.getElementById('resultBanner');
      banner.style.display = 'none';
      banner.className = 'result-banner';

      init();
      renderArray();
      updateInfo(`Searching for ${target}. Array has ${ARRAY.length} elements. Press Step ▶ to begin.`);

      document.getElementById('stepBtn').disabled = false;
      document.getElementById('startBtn').disabled = true;
    }

    // ── Single step ───────────────────────────────────────────────────────────
    function step() {
      if (done) return;
      stepCount++;

      if (lo > hi) {
        // Not found
        finish(false);
        return;
      }

      mid = Math.floor((lo + hi) / 2);
      renderArray();

      const midVal = ARRAY[mid];

      if (midVal === target) {
        // Found!
        foundIndex = mid;
        finish(true);
      } else if (midVal < target) {
        updateInfo(
          `Step ${stepCount}: arr[${mid}] = ${midVal} < ${target} → target is in the RIGHT half. Moving LO to ${mid + 1}.`
        );
        lo = mid + 1;
      } else {
        updateInfo(
          `Step ${stepCount}: arr[${mid}] = ${midVal} > ${target} → target is in the LEFT half. Moving HI to ${mid - 1}.`
        );
        hi = mid - 1;
      }

      // Check if next iteration will fail
      if (!done && lo > hi) {
        // Will finish on next step — let it happen naturally
      }
    }

    // ── Finish ────────────────────────────────────────────────────────────────
    function finish(found) {
      done = true;
      document.getElementById('stepBtn').disabled = true;
      document.getElementById('startBtn').disabled = false;

      const banner = document.getElementById('resultBanner');

      if (found) {
        renderArray(true);
        updateInfo(`✅ Found ${target} at index ${foundIndex} in ${stepCount} step(s)!`);
        banner.textContent = `🎉 Found ${target} at index ${foundIndex}!`;
        banner.className = 'result-banner found-banner';
      } else {
        // Grey everything out
        mid = null;
        lo = ARRAY.length; // forces all out-of-range
        hi = -1;
        renderArray(false);
        updateInfo(`❌ ${target} is not in the array. Search ended after ${stepCount} step(s).`);
        banner.textContent = `❌ ${target} not found in the array.`;
        banner.className = 'result-banner not-found-banner';
      }

      banner.style.display = 'block';
    }

    // ── Reset ─────────────────────────────────────────────────────────────────
    function resetAll() {
      init();
      mid = null;

      document.getElementById('targetInput').value = '';
      document.getElementById('stepBtn').disabled = true;
      document.getElementById('startBtn').disabled = false;

      const banner = document.getElementById('resultBanner');
      banner.style.display = 'none';

      // Render clean array
      const container = document.getElementById('arrayContainer');
      const pointerRow = document.getElementById('pointerRow');
      container.innerHTML = '';
      pointerRow.innerHTML = '';

      ARRAY.forEach((val, i) => {
        const box = document.createElement('div');
        box.className = 'box';
        box.id = `box-${i}`;

        const idxLabel = document.createElement('span');
        idxLabel.className = 'index-label';
        idxLabel.textContent = i;

        box.appendChild(idxLabel);
        box.appendChild(document.createTextNode(val));
        container.appendChild(box);

        const cell = document.createElement('div');
        cell.className = 'pointer-cell';
        pointerRow.appendChild(cell);
      });

      updateInfo('Enter a target value and press Search to begin.');
      document.getElementById('infoVars').innerHTML = '';
    }

    // ── Boot ──────────────────────────────────────────────────────────────────
    resetAll();
  </script>
</body>
</html>
```

## What's included

**Visual elements:**
- 16 pre-sorted numbers displayed as styled boxes with index labels above each one
- Pointer labels (`LO`, `HI`, `MID`) shown above the boxes that update each step
- Color coding for every state — blue for in-range, gold for the middle element, green for found, and dimmed/faded for eliminated elements

**Controls:**
- **Target input** — type any integer to search for
- **Search button** — initializes the algorithm and enables stepping
- **Step ▶ button** — advances one iteration at a time
- **Reset button** — clears everything back to the start

**Info panel** shows:
- A human-readable explanation of each decision (left half vs right half)
- Live `LO`, `MID`, and `HI` variable values
- A result banner (green for found, red for not found) with the index or a not-found message

