  </div>

  <div class="info-panel">
    <h3>Algorithm State</h3>
    <div class="info-row">
      <span class="info-label">Left pointer</span>
      <span class="info-value" id="infoLeft">—</span>
    </div>
    <div class="info-row">
      <span class="info-label">Right pointer</span>
      <span class="info-value" id="infoRight">—</span>
    </div>
    <div class="info-row">
      <span class="info-label">Mid index</span>
      <span class="info-value" id="infoMid">—</span>
    </div>
    <div class="info-row">
      <span class="info-label">Mid value</span>
      <span class="info-value" id="infoMidVal">—</span>
    </div>
    <div class="info-row">
      <span class="info-label">Comparisons</span>
      <span class="info-value" id="infoComparisons">0</span>
    </div>
  </div>

  <div id="statusMsg" class="status-message status-searching">
    Enter a target and press Step
  </div>

  <br/>

  <div class="step-log" id="stepLog">
    <p>Log will appear here as you step through...</p>
  </div>

  <script>
    const array = [3, 7, 11, 15, 19, 23, 27, 31, 38, 42, 47, 53, 61, 68, 74, 80];

    let left, right, mid, target, comparisons, done, foundIndex;

    function init() {
      left = 0;
      right = array.length - 1;
      mid = -1;
      target = null;
      comparisons = 0;
      done = false;
      foundIndex = -1;
    }

    init();

    function renderArray(highlightLeft, highlightRight, highlightMid, highlightFound) {
      const container = document.getElementById('arrayContainer');
      container.innerHTML = '';
      array.forEach((val, i) => {
        const box = document.createElement('div');
        box.className = 'box';

        const label = document.createElement('span');
        label.className = 'index-label';
        label.textContent = i;
        box.appendChild(label);

        box.appendChild(document.createTextNode(val));

        if (highlightFound !== undefined && i === highlightFound) {
          box.classList.add('found');
        } else if (highlightMid !== undefined && i === highlightMid) {
          box.classList.add('mid');
        } else if (highlightLeft !== undefined && i >= highlightLeft && i <= highlightRight) {
          box.classList.add('in-range');
        } else if (highlightLeft !== undefined) {
          box.classList.add('eliminated');
        }

        container.appendChild(box);
      });
    }

    function updateInfo(l, r, m, mv, c) {
      document.getElementById('infoLeft').textContent = l !== undefined ? l : '—';
      document.getElementById('infoRight').textContent = r !== undefined ? r : '—';
      document.getElementById('infoMid').textContent = m !== undefined && m >= 0 ? m : '—';
      document.getElementById('infoMidVal').textContent = mv !== undefined && mv >= 0 ? mv : '—';
      document.getElementById('infoComparisons').textContent = c !== undefined ? c : 0;
    }

    function setStatus(type, msg) {
      const el = document.getElementById('statusMsg');
      el.className = 'status-message';
      el.classList.add(type);
      el.textContent = msg;
    }

    function addLog(msg) {
      const log = document.getElementById('stepLog');
      if (log.children.length === 1 && log.children[0].textContent.includes('Log will')) {
        log.innerHTML = '';
      }
      const p = document.createElement('p');
      p.innerHTML = msg;
      log.appendChild(p);
      log.scrollTop = log.scrollHeight;
    }

    function step() {
      if (done) return;

      const rawTarget = document.getElementById('targetInput').value.trim();
      if (rawTarget === '') {
        setStatus('status-searching', '⚠️ Please enter a target value!');
        return;
      }

      const parsedTarget = parseInt(rawTarget);
      if (isNaN(parsedTarget)) {
        setStatus('status-searching', '⚠️ Please enter a valid number!');
        return;
      }

      if (target === null) {
        target = parsedTarget;
        document.getElementById('stepLog').innerHTML = '';
        addLog(`🎯 Searching for <span>${target}</span> in array of ${array.length} elements.`);
        addLog(`📐 Initial range: left=<span>0</span>, right=<span>${array.length - 1}</span>`);
        renderArray(left, right, -1);
        updateInfo(left, right, '—', '—', 0);
        setStatus('status-searching', `Searching for ${target}...`);
        return;
      }

      if (target !== parsedTarget) {
        target = parsedTarget;
        init();
        target = parsedTarget;
        document.getElementById('stepLog').innerHTML = '';
        addLog(`🎯 New target: <span>${target}</span>. Restarting search.`);
        renderArray(left, right, -1);
        updateInfo(left, right, '—', '—', 0);
        setStatus('status-searching', `Searching for ${target}...`);
        return;
      }

      if (left > right) {
        done = true;
        setStatus('status-not-found', `❌ ${target} not found in array`);
        addLog(`🔚 Search complete: <span>${target}</span> is NOT in the array.`);
        document.getElementById('stepBtn').disabled = true;
        renderArray(0, -1, -1);
        return;
      }

      mid = Math.floor((left + right) / 2);
      comparisons++;

      renderArray(left, right, mid);
      updateInfo(left, right, mid, array[mid], comparisons);

      if (array[mid] === target) {
        done = true;
        foundIndex = mid;
        renderArray(left, right, -1, mid);
        setStatus('status-found', `✅ Found ${target} at index ${mid}!`);
        addLog(`✅ <span>FOUND!</span> array[${mid}] = ${array[mid]} equals target <span>${target}</span>.`);
        document.getElementById('stepBtn').disabled = true;
      } else if (array[mid] < target) {
        addLog(`Step ${comparisons}: mid=<span>${mid}</span>, array[${mid}]=<span>${array[mid]}</span> &lt; <span>${target}</span> → search right half`);
        left = mid + 1;
        setStatus('status-searching', `array[${mid}]=${array[mid]} < ${target} → go right`);
      } else {
        addLog(`Step ${comparisons}: mid=<span>${mid}</span>, array[${mid}]=<span>${array[mid]}</span> &gt; <span>${target}</span> → search left half`);
        right = mid - 1;
        setStatus('status-searching', `array[${mid}]=${array[mid]} > ${target} → go left`);
      }

      if (!done && left > right) {
        done = true;
        setStatus('status-not-found', `❌ ${target} not found in array`);
        addLog(`🔚 Search complete: <span>${target}</span> is NOT in the array.`);
        document.getElementById('stepBtn').disabled = true;
        renderArray(0, -1, -1);
        updateInfo(left, right, mid, array[mid], comparisons);
      }
    }

    function reset() {
      init();
      document.getElementById('targetInput').value = '';
      document.getElementById('stepBtn').disabled = false;
      document.getElementById('stepLog').innerHTML = '<p>Log will appear here as you step through...</p>';
      renderArray();
      updateInfo();
      setStatus('status-searching', 'Enter a target and press Step');
    }

    renderArray();
    updateInfo();
  </script>
</body>
</html>
