<body>

  <h1>Binary Search Visualizer</h1>
  <p class="subtitle">Step through binary search on a sorted array</p>

  <div class="controls">
    <label for="targetInput">Target value:</label>
    <input type="number" id="targetInput" value="37" min="1" max="99" />
    <button id="stepBtn">▶ Step</button>
    <button id="resetBtn">↺ Reset</button>
  </div>

  <div class="info-panel">
    <h2>Search State</h2>
    <div class="info-grid">
      <div class="info-item low">
        <div class="val" id="infoLow">—</div>
        <div class="key">Low (idx)</div>
      </div>
      <div class="info-item mid">
        <div class="val" id="infoMid">—</div>
        <div class="key">Mid (idx)</div>
      </div>
      <div class="info-item high">
        <div class="val" id="infoHigh">—</div>
        <div class="key">High (idx)</div>
      </div>
    </div>
    <div class="step-log" id="stepLog">Press <span>Step</span> to begin the search.</div>
  </div>

  <div class="array-wrapper">
    <div class="array-container" id="arrayContainer">
      <div class="range-bar" id="rangeBar"></div>
    </div>
  </div>

  <div class="result-banner" id="resultBanner"></div>

  <div class="legend">
    <div class="legend-item"><div class="legend-dot inactive"></div> Out of range</div>
    <div class="legend-item"><div class="legend-dot in-range"></div> In range</div>
    <div class="legend-item"><div class="legend-dot mid-dot"></div> Mid (comparing)</div>
    <div class="legend-item"><div class="legend-dot found-dot"></div> Found!</div>
  </div>

  <script>
    // --- Data ---
    const ARRAY = [2, 5, 8, 12, 16, 23, 29, 34, 37, 41, 45, 50, 56, 62, 67, 73, 78, 84, 91, 97];
    const BOX_WIDTH  = 58;
    const BOX_GAP    = 8;

    // --- State ---
    let low, high, mid, target, done, found, stepCount;
    let boxes = [];

    // --- DOM ---
    const container   = document.getElementById('arrayContainer');
    const rangeBar    = document.getElementById('rangeBar');
    const stepBtn     = document.getElementById('stepBtn');
    const resetBtn    = document.getElementById('resetBtn');
    const targetInput = document.getElementById('targetInput');
    const infoLow     = document.getElementById('infoLow');
    const infoMid     = document.getElementById('infoMid');
    const infoHigh    = document.getElementById('infoHigh');
    const stepLog     = document.getElementById('stepLog');
    const resultBanner = document.getElementById('resultBanner');

    // --- Build array UI ---
    function buildArray() {
      // Remove old boxes (keep rangeBar)
      const oldBoxes = container.querySelectorAll('.box-wrapper');
      oldBoxes.forEach(b => b.remove());

      boxes = [];
      ARRAY.forEach((val, i) => {
        const wrapper = document.createElement('div');
        wrapper.className = 'box-wrapper';

        const label = document.createElement('div');
        label.className = 'box-label';
        label.textContent = '';

        const box = document.createElement('div');
        box.className = 'box';
        box.textContent = val;

        const idx = document.createElement('div');
        idx.className = 'box-index';
        idx.textContent = i;

        wrapper.appendChild(label);
        wrapper.appendChild(box);
        wrapper.appendChild(idx);
        container.appendChild(wrapper);

        boxes.push({ wrapper, box, label });
      });
    }

    // --- Reset ---
    function reset() {
      low       = 0;
      high      = ARRAY.length - 1;
      mid       = null;
      done      = false;
      found     = false;
      stepCount = 0;
      target    = parseInt(targetInput.value, 10);

      if (isNaN(target)) target = 37;

      buildArray();
      renderState(false);

      infoLow.textContent  = '—';
      infoMid.textContent  = '—';
      infoHigh.textContent = '—';
      stepLog.innerHTML    = `Press <span>Step</span> to begin searching for <span>${target}</span>.`;
      resultBanner.className = 'result-banner';
      resultBanner.textContent = '';
      stepBtn.disabled = false;
    }

    // --- Render visual state ---
    function renderState(showMid) {
      boxes.forEach((b, i) => {
        b.box.className = 'box';
        b.label.className = 'box-label';
        b.label.textContent = '';

        if (done && found && i === mid) {
          b.box.classList.add('found');
          b.label.classList.add('show-mid');
          b.label.textContent = 'FOUND';
        } else if (done && !found) {
          // Highlight last range as not found
          if (i >= low && i <= high + 1) {
            // just leave as inactive
          }
          b.box.classList.add('');
        } else if (showMid && i === mid) {
          b.box.classList.add('mid');
          // labels
          let lbl = 'MID';
          if (i === low && i === high) lbl = 'L/M/H';
          else if (i === low) lbl = 'L/M';
          else if (i === high) lbl = 'M/H';
          b.label.classList.add('show-mid');
          b.label.textContent = lbl;
        } else if (showMid && i >= low && i <= high) {
          b.box.classList.add('in-range');
          if (i === low && i === high) {
            b.label.classList.add('show-low', 'show-high');
            b.label.textContent = 'L/H';
          } else if (i === low) {
            b.label.classList.add('show-low');
            b.label.textContent = 'LOW';
          } else if (i === high) {
            b.label.classList.add('show-high');
            b.label.textContent = 'HIGH';
          }
        } else if (!showMid && i >= low && i <= high) {
          b.box.classList.add('in-range');
          if (i === low && i === high) {
            b.label.classList.add('show-low', 'show-high');
            b.label.textContent = 'L/H';
          } else if (i === low) {
            b.label.classList.add('show-low');
            b.label.textContent = 'LOW';
          } else if (i === high) {
            b.label.classList.add('show-high');
            b.label.textContent = 'HIGH';
          }
        }
      });

      updateRangeBar();
    }

    function updateRangeBar() {
      if (done || low > high) {
        rangeBar.classList.remove('visible');
        return;
      }

      // Position range bar under the active range
      const containerRect = container.getBoundingClientRect();

      // Each box-wrapper has fixed width = BOX_WIDTH, gap = BOX_GAP
      const totalBoxWidth = BOX_WIDTH + BOX_GAP;

      // Calculate offset from center of container
      const totalWidth = ARRAY.length * totalBoxWidth - BOX_GAP;
      const startX = (container.offsetWidth - totalWidth) / 2;

      const barLeft  = startX + low  * totalBoxWidth;
      const barRight = startX + high * totalBoxWidth + BOX_WIDTH;

      rangeBar.style.left  = barLeft + 'px';
      rangeBar.style.width = (barRight - barLeft) + 'px';
      rangeBar.classList.add('visible');
    }

    // --- Step ---
    function step() {
      if (done) return;

      stepCount++;

      if (low > high) {
        // Not found
        done  = true;
        found = false;
        renderState(false);
        infoLow.textContent  = '—';
        infoMid.textContent  = '—';
        infoHigh.textContent = '—';
        stepLog.innerHTML = `Search complete after <span>${stepCount - 1}</span> step(s).`;
        showResult(false);
        stepBtn.disabled = true;
        return;
      }

      mid = Math.floor((low + high) / 2);
      const midVal = ARRAY[mid];

      infoLow.textContent  = low;
      infoMid.textContent  = mid;
      infoHigh.textContent = high;

      renderState(true);

      if (midVal === target) {
        done  = true;
        found = true;
        stepLog.innerHTML = `Step <span>${stepCount}</span>: mid=<span>${mid}</span>, arr[${mid}]=<span>${midVal}</span> — 🎉 Found <span>${target}</span>!`;
        renderState(true);
        showResult(true, mid);
        stepBtn.disabled = true;
      } else if (midVal < target) {
        stepLog.innerHTML = `Step <span>${stepCount}</span>: mid=<span>${mid}</span>, arr[${mid}]=<span>${midVal}</span> &lt; <span>${target}</span> → search <span>right half</span>`;
        low = mid + 1;
      } else {
        stepLog.innerHTML = `Step <span>${stepCount}</span>: mid=<span>${mid}</span>, arr[${mid}]=<span>${midVal}</span> &gt; <span>${target}</span> → search <span>left half</span>`;
        high = mid - 1;
      }
    }

    function showResult(wasFound, idx) {
      const banner = resultBanner;
      if (wasFound) {
        banner.className = 'result-banner found';
        banner.textContent = `✅ Found ${target} at index ${idx}!`;
      } else {
        banner.className = 'result-banner not-found';
        banner.textContent = `❌ ${target} is not in the array.`;
      }
    }

    // --- Events ---
    stepBtn.addEventListener('click', step);
    resetBtn.addEventListener('click', reset);
    targetInput.addEventListener('keydown', e => {
      if (e.key === 'Enter') reset();
    });

    window.addEventListener('resize', updateRangeBar);

    // --- Init ---
    reset();
  </script>
</body>
</html>
```

This single HTML file includes:

### Features
- **20-element sorted array** displayed as styled boxes
- **Step-by-step execution** — each click advances exactly one iteration
- **Color coding:**
  - 🔵 **In-range** boxes (current search window)
  - 🟡 **Mid element** (currently being compared, lifts up)
  - 🟢 **Found** element (glows green with pulse animation)
  - ⬛ **Out-of-range** boxes (dimmed/inactive)
- **Range bar** — a gradient line spans the active search window
- **Info panel** showing current `low`, `mid`, and `high` indices
- **Step log** explaining each comparison in plain English
- **Result banner** — green ✅ or red ❌ when the search concludes
- **Reset button** — restarts with whatever target is in the input field
- **Labels** on boxes (LOW / MID / HIGH) for clarity

