    .ptr-mid  { color: #7b6cf6; }
    .ptr-high { color: #e91e63; }
    .ptr-both-lh { color: #ff7043; }
  </style>
</head>
<body>

  <h1>Binary Search Visualizer</h1>
  <p class="subtitle">Watch how binary search narrows down the search range step by step</p>

  <div class="controls">
    <label for="targetInput">Target value:</label>
    <input type="number" id="targetInput" value="37" min="1" max="99" />
    <button id="stepBtn">▶ Step</button>
    <button id="resetBtn">↺ Reset</button>
  </div>

  <div class="legend">
    <div class="legend-item"><div class="legend-dot dot-range"></div> In search range</div>
    <div class="legend-item"><div class="legend-dot dot-mid"></div> Mid (comparing)</div>
    <div class="legend-item"><div class="legend-dot dot-found"></div> Found!</div>
    <div class="legend-item"><div class="legend-dot dot-elim"></div> Eliminated</div>
  </div>

  <div class="pointer-row" id="pointerRow"></div>
  <div class="array-container" id="arrayContainer"></div>

  <div class="result-banner" id="resultBanner"></div>

  <div class="info-panel">
    <div class="step-count" id="stepCount">Ready</div>
    <div class="message" id="message">Enter a target and press <strong>Step</strong> to begin.</div>
  </div>

  <script>
    // Sorted array to search through
    const ARRAY = [2, 5, 8, 12, 16, 19, 23, 27, 31, 35, 37, 42, 46, 50, 55, 58, 63, 67, 71, 76];

    let low, high, mid, step, target, done, foundIndex;

    function init() {
      low = 0;
      high = ARRAY.length - 1;
      mid = -1;
      step = 0;
      done = false;
      foundIndex = -1;
      target = parseInt(document.getElementById('targetInput').value);

      document.getElementById('resultBanner').className = 'result-banner';
      document.getElementById('resultBanner').textContent = '';
      document.getElementById('stepBtn').disabled = false;
      document.getElementById('stepCount').textContent = 'Ready';
      document.getElementById('message').innerHTML =
        `Searching for <span class="highlight">${target}</span> in an array of ${ARRAY.length} elements. Press <strong>Step</strong> to begin.`;

      renderArray(-1, -1, -1, false);
      renderPointers(-1, -1, -1, false);
    }

    function renderArray(lo, hi, midIdx, isFound) {
      const container = document.getElementById('arrayContainer');
      container.innerHTML = '';
      ARRAY.forEach((val, i) => {
        const box = document.createElement('div');
        box.className = 'box';

        const idx = document.createElement('span');
        idx.className = 'index';
        idx.textContent = `[${i}]`;
        box.appendChild(idx);

        const num = document.createElement('span');
        num.textContent = val;
        box.appendChild(num);

        if (isFound && i === midIdx) {
          box.classList.add('found');
        } else if (lo === -1 && hi === -1) {
          // initial state — all neutral
        } else if (i === midIdx) {
          box.classList.add('mid');
        } else if (i >= lo && i <= hi) {
          box.classList.add('in-range');
        } else {
          box.classList.add('eliminated');
        }

        container.appendChild(box);
      });
    }

    function renderPointers(lo, hi, midIdx, isFound) {
      const row = document.getElementById('pointerRow');
      row.innerHTML = '';
      ARRAY.forEach((_, i) => {
        const lbl = document.createElement('div');
        lbl.className = 'pointer-label';

        const tags = [];
        if (lo !== -1) {
          const isLow  = i === lo  && !isFound;
          const isHigh = i === hi  && !isFound;
          const isMid  = i === midIdx;

          if (isLow && isHigh && isMid) {
            lbl.textContent = 'L/M/H';
            lbl.classList.add('ptr-both-lh');
          } else if (isLow && isHigh) {
            lbl.textContent = 'L / H';
            lbl.classList.add('ptr-both-lh');
          } else if (isLow && isMid) {
            lbl.textContent = 'L / M';
            lbl.classList.add('ptr-mid');
          } else if (isHigh && isMid) {
            lbl.textContent = 'M / H';
            lbl.classList.add('ptr-mid');
          } else if (isLow) {
            lbl.textContent = 'LOW';
            lbl.classList.add('ptr-low');
          } else if (isHigh) {
            lbl.textContent = 'HIGH';
            lbl.classList.add('ptr-high');
          } else if (isMid) {
            lbl.textContent = 'MID';
            lbl.classList.add('ptr-mid');
          }
        }

        row.appendChild(lbl);
      });
    }

    function stepSearch() {
      if (done) return;

      if (low > high) {
        // Not found
        done = true;
        document.getElementById('stepBtn').disabled = true;
        document.getElementById('stepCount').textContent = `Step ${step} — Complete`;
        document.getElementById('message').innerHTML =
          `<span class="notfound-text">✗ Not Found</span> — Target <span class="highlight">${target}</span> is not in the array.`;
        const banner = document.getElementById('resultBanner');
        banner.textContent = `✗ ${target} was NOT FOUND in the array`;
        banner.className = 'result-banner not-found';
        renderArray(low, high, -1, false);
        renderPointers(-1, -1, -1, false);
        return;
      }

      step++;
      mid = Math.floor((low + high) / 2);

      document.getElementById('stepCount').textContent = `Step ${step}`;

      if (ARRAY[mid] === target) {
        // Found
        done = true;
        foundIndex = mid;
        document.getElementById('stepBtn').disabled = true;
        document.getElementById('message').innerHTML =
          `<span class="found-text">✓ Found!</span> — <span class="highlight">${target}</span> is at index <span class="found-text">[${mid}]</span>.`;
        const banner = document.getElementById('resultBanner');
        banner.textContent = `✓ ${target} FOUND at index [${mid}]`;
        banner.className = 'result-banner found';
        renderArray(low, high, mid, true);
        renderPointers(low, high, mid, true);
      } else if (ARRAY[mid] < target) {
        document.getElementById('message').innerHTML =
          `arr[<span class="highlight">${mid}</span>] = <span class="highlight">${ARRAY[mid]}</span> &lt; <span class="highlight">${target}</span> &rarr; Search <strong>right half</strong>. New LOW = <span class="highlight">${mid + 1}</span>`;
        renderArray(low, high, mid, false);
        renderPointers(low, high, mid, false);
        low = mid + 1;
      } else {
        document.getElementById('message').innerHTML =
          `arr[<span class="highlight">${mid}</span>] = <span class="highlight">${ARRAY[mid]}</span> &gt; <span class="highlight">${target}</span> &rarr; Search <strong>left half</strong>. New HIGH = <span class="highlight">${mid - 1}</span>`;
        renderArray(low, high, mid, false);
        renderPointers(low, high, mid, false);
        high = mid - 1;
      }
    }

    document.getElementById('stepBtn').addEventListener('click', stepSearch);
    document.getElementById('resetBtn').addEventListener('click', init);
    document.getElementById('targetInput').addEventListener('keydown', (e) => {
      if (e.key === 'Enter') init();
    });

    // Boot
    init();
  </script>
</body>
</html>
```

This self-contained HTML file includes:

### Features
- **20-element sorted array** displayed as styled boxes with index labels
- **Pointer labels** (LOW, MID, HIGH) shown above each box so you can track all three pointers simultaneously
- **Step-by-step control** — each click advances exactly one iteration
- **Color coding:**
  - 🟣 **Purple glow** — current MID element being compared
  - 🔵 **Blue tint** — elements still in the active search range
  - ⬛ **Dimmed/shrunk** — eliminated elements
  - 🟢 **Green glow + animation** — target found
- **Info panel** explains what happened each step (comparison result and which half to search next)
- **Result banner** clearly shows Found ✓ or Not Found ✗ when complete
- **Reset button** and pressing Enter in the input field restarts the search

