<body>

  <h1>Binary Search Visualizer</h1>
  <p class="subtitle">Step through the algorithm one iteration at a time</p>

  <div class="controls">
    <label for="targetInput">Target value:</label>
    <input type="number" id="targetInput" value="37" min="1" max="99" />
    <button id="startBtn">▶ Start</button>
    <button id="stepBtn" disabled>⏭ Step</button>
    <button id="resetBtn">↺ Reset</button>
  </div>

  <div class="array-wrapper">
    <div class="array-container" id="arrayContainer"></div>
  </div>

  <div class="info-panel">
    <div class="step-info" id="stepInfo">Enter a target and press Start.</div>
    <div id="resultMsg"></div>
  </div>

  <div class="legend">
    <div class="legend-item"><div class="legend-box leg-range"></div> Search range</div>
    <div class="legend-item"><div class="legend-box leg-mid"></div> Mid element</div>
    <div class="legend-item"><div class="legend-box leg-found"></div> Found</div>
    <div class="legend-item"><div class="legend-box leg-elim"></div> Eliminated</div>
  </div>

<script>
  const ARRAY = [3, 7, 11, 15, 19, 23, 27, 31, 37, 41, 46, 52, 58, 63, 70, 76];

  let lo, hi, mid, target, done, foundIndex, stepCount;

  const container  = document.getElementById('arrayContainer');
  const stepInfo   = document.getElementById('stepInfo');
  const resultMsg  = document.getElementById('resultMsg');
  const startBtn   = document.getElementById('startBtn');
  const stepBtn    = document.getElementById('stepBtn');
  const resetBtn   = document.getElementById('resetBtn');
  const targetInput = document.getElementById('targetInput');

  function buildArray() {
    container.innerHTML = '';
    ARRAY.forEach((val, i) => {
      const wrapper = document.createElement('div');
      wrapper.className = 'box-wrapper';
      wrapper.id = `wrapper-${i}`;

      const ptr = document.createElement('div');
      ptr.className = 'pointer-label';
      ptr.id = `ptr-${i}`;

      const box = document.createElement('div');
      box.className = 'box';
      box.id = `box-${i}`;
      box.textContent = val;

      const idx = document.createElement('div');
      idx.className = 'index-label';
      idx.textContent = `[${i}]`;

      wrapper.appendChild(ptr);
      wrapper.appendChild(box);
      wrapper.appendChild(idx);
      container.appendChild(wrapper);
    });
  }

  function resetState() {
    lo = hi = mid = target = done = foundIndex = stepCount = undefined;
    stepBtn.disabled = true;
    resultMsg.innerHTML = '';
    stepInfo.innerHTML = 'Enter a target and press <strong>Start</strong>.';
    buildArray();
  }

  function renderState() {
    ARRAY.forEach((_, i) => {
      const box = document.getElementById(`box-${i}`);
      const ptr = document.getElementById(`ptr-${i}`);

      // Reset classes
      box.className = 'box';
      ptr.textContent = '';
      ptr.className = 'pointer-label';

      if (done && foundIndex === i) {
        box.classList.add('found');
      } else if (i < lo || i > hi) {
        box.classList.add('eliminated');
      } else if (i === mid) {
        box.classList.add('mid');
      } else {
        box.classList.add('active-range');
      }

      // Pointer labels
      const labels = [];
      const classes = [];
      if (i === lo)  { labels.push('lo');  classes.push('ptr-lo'); }
      if (i === mid) { labels.push('mid'); classes.push('ptr-mid'); }
      if (i === hi)  { labels.push('hi');  classes.push('ptr-hi'); }

      if (labels.length) {
        ptr.textContent = labels.join(' / ');
        ptr.className = 'pointer-label ' + classes.join(' ');
      }
    });
  }

  function updateInfo(msg) {
    stepInfo.innerHTML = msg;
  }

  function startSearch() {
    const val = parseInt(targetInput.value, 10);
    if (isNaN(val)) {
      alert('Please enter a valid number.');
      return;
    }

    target     = val;
    lo         = 0;
    hi         = ARRAY.length - 1;
    mid        = Math.floor((lo + hi) / 2);
    done       = false;
    foundIndex = -1;
    stepCount  = 0;

    buildArray();
    renderState();

    updateInfo(
      `Searching for <span class="val-target">${target}</span>. ` +
      `Initial range: <span class="val-lo">lo=${lo}</span>, ` +
      `<span class="val-hi">hi=${hi}</span>, ` +
      `<span class="val-mid">mid=${mid}</span> → arr[${mid}] = ${ARRAY[mid]}`
    );

    resultMsg.innerHTML = '';
    stepBtn.disabled = false;
    startBtn.disabled = true;
  }

  function step() {
    if (done) return;

    stepCount++;
    const midVal = ARRAY[mid];

    if (midVal === target) {
      foundIndex = mid;
      done = true;
      renderState();
      updateInfo(`Step ${stepCount}: arr[<span class="val-mid">${mid}</span>] = <span class="val-mid">${midVal}</span> equals target <span class="val-target">${target}</span>. 🎯 Found!`);
      resultMsg.innerHTML = `<div class="result-msg result-found">✅ Found ${target} at index [${mid}]</div>`;
      stepBtn.disabled = true;
      startBtn.disabled = false;
      return;
    }

    let comparison;
    if (midVal < target) {
      comparison = `arr[${mid}]=${midVal} &lt; ${target} → move <span class="val-lo">lo</span> right`;
      lo = mid + 1;
    } else {
      comparison = `arr[${mid}]=${midVal} &gt; ${target} → move <span class="val-hi">hi</span> left`;
      hi = mid - 1;
    }

    if (lo > hi) {
      done = true;
      renderState();
      updateInfo(`Step ${stepCount}: ${comparison}. Search space exhausted.`);
      resultMsg.innerHTML = `<div class="result-msg result-notfound">❌ ${target} not found in array</div>`;
      stepBtn.disabled = true;
      startBtn.disabled = false;
      return;
    }

    mid = Math.floor((lo + hi) / 2);
    renderState();
    updateInfo(
      `Step ${stepCount}: ${comparison}. ` +
      `New range: <span class="val-lo">lo=${lo}</span>, ` +
      `<span class="val-hi">hi=${hi}</span>, ` +
      `<span class="val-mid">mid=${mid}</span> → arr[${mid}] = ${ARRAY[mid]}`
    );
  }

  startBtn.addEventListener('click', startSearch);
  stepBtn.addEventListener('click', step);
  resetBtn.addEventListener('click', resetState);
  targetInput.addEventListener('keydown', e => { if (e.key === 'Enter') startSearch(); });

  // Init
  buildArray();
</script>
</body>
</html>
```

This self-contained file includes everything you need:

### Features
- **16-element sorted array** displayed as a row of styled boxes
- **Step-by-step execution** — each click of ⏭ Step advances exactly one iteration
- **Visual highlights:**
  - 🟣 **Active search range** — dimly highlighted in purple
  - 🔵 **Mid element** — bright cyan with glow and lift animation
  - 🟢 **Found** — green glow when target is located
  - ⬛ **Eliminated** — faded out when outside the current range
- **Pointer labels** (lo / mid / hi) shown above each relevant box
- **Info panel** describes each comparison in plain text with color-coded values
- **Found / Not Found** result banner at the end
- **Reset & Restart** buttons to try different targets

