<body>

<h1>Binary Search</h1>
<p class="subtitle">Step through the algorithm one iteration at a time</p>

<div class="array-input-row">
  <input type="text" id="customArray" placeholder="Custom sorted array, e.g: 2, 5, 8, 12, 16, 23, 38, 45" />
  <button onclick="applyCustomArray()">Apply</button>
  <button id="btnRandom" onclick="generateRandom()">Random Array</button>
</div>
<div id="errorMsg" class="error-msg"></div>

<div class="controls">
  <label>Target:</label>
  <input type="number" id="targetInput" value="23" />
  <button id="btnStart" onclick="startSearch()">Start Search</button>
  <button id="btnStep" onclick="stepSearch()" disabled>Step →</button>
  <button id="btnReset" onclick="resetAll()">Reset</button>
</div>

<div class="array-wrapper">
  <div class="array-row" id="arrayRow"></div>
</div>

<div class="info-panel">
  <div class="step-counter" id="stepCounter">Ready</div>
  <div class="log-entry" id="logEntry">Set a target value and press <strong>Start Search</strong> to begin.</div>
  <div class="result-banner" id="resultBanner"></div>
</div>

<div class="legend">
  <div class="legend-item">
    <div class="legend-box" style="background:#7c6fff33;border-color:#7c6fff"></div> Middle element
  </div>
  <div class="legend-item">
    <div class="legend-box" style="background:#1e1e3a;border-color:#4a4a7a"></div> Search range
  </div>
  <div class="legend-item">
    <div class="legend-box" style="background:#00e57633;border-color:#00e576"></div> Found
  </div>
  <div class="legend-item">
    <div class="legend-box" style="background:#0f0f18;border-color:#1a1a22"></div> Eliminated
  </div>
</div>

<script>
  let arr = [2, 5, 8, 12, 16, 23, 38, 45, 56, 72, 91];
  let lo, hi, mid, target, stepCount, done, steps;

  function generateRandom() {
    const size = Math.floor(Math.random() * 8) + 8;
    const set = new Set();
    while (set.size < size) set.add(Math.floor(Math.random() * 150) + 1);
    arr = [...set].sort((a, b) => a - b);
    document.getElementById('customArray').value = arr.join(', ');
    resetAll();
    renderArray();
  }

  function applyCustomArray() {
    const raw = document.getElementById('customArray').value;
    const errEl = document.getElementById('errorMsg');
    const parts = raw.split(',').map(s => s.trim()).filter(s => s !== '');
    const nums = parts.map(Number);
    if (nums.some(isNaN)) { errEl.textContent = '✖ All values must be numbers.'; return; }
    if (nums.length < 2) { errEl.textContent = '✖ Please enter at least 2 numbers.'; return; }
    for (let i = 1; i < nums.length; i++) {
      if (nums[i] <= nums[i-1]) { errEl.textContent = '✖ Array must be strictly sorted in ascending order.'; return; }
    }
    errEl.textContent = '';
    arr = nums;
    resetAll();
    renderArray();
  }

  function renderArray(state) {
    const row = document.getElementById('arrayRow');
    row.innerHTML = '';
    arr.forEach((val, i) => {
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.id = `cell-${i}`;
      cell.innerHTML = `${val}<span class="idx">${i}</span>`;

      if (state) {
        if (state.found && i === state.mid) {
          cell.classList.add('found');
        } else if (i < state.lo || i > state.hi) {
          cell.classList.add('eliminated');
        } else if (i === state.mid) {
          cell.classList.add('mid');
        } else {
          cell.classList.add('in-range');
        }

        // Pointer labels
        const ptrs = [];
        if (i === state.lo) ptrs.push({ cls: 'ptr-lo', label: 'LO' });
        if (i === state.hi) ptrs.push({ cls: 'ptr-hi', label: 'HI' });
        if (i === state.mid) ptrs.push({ cls: 'ptr-mid', label: 'MID' });

        ptrs.forEach((p, pi) => {
          const ptr = document.createElement('span');
          ptr.className = `pointer ${p.cls}`;
          ptr.style.bottom = `${-48 - pi * 18}px`;
          ptr.textContent = p.label;
          cell.appendChild(ptr);
        });
      }

      row.appendChild(cell);
    });
  }

  function precomputeSteps(arr, target) {
    const steps = [];
    let lo = 0, hi = arr.length - 1;
    while (lo <= hi) {
      const mid = Math.floor((lo + hi) / 2);
      steps.push({ lo, hi, mid, found: arr[mid] === target });
      if (arr[mid] === target) break;
      else if (arr[mid] < target) lo = mid + 1;
      else hi = mid - 1;
    }
    if (steps.length === 0 || !steps[steps.length - 1].found) {
      steps.push({ lo, hi, mid: -1, found: false, notFound: true });
    }
    return steps;
  }

  function startSearch() {
    const tVal = parseInt(document.getElementById('targetInput').value);
    if (isNaN(tVal)) { alert('Please enter a valid target number.'); return; }
    target = tVal;
    stepCount = 0;
    done = false;
    steps = precomputeSteps(arr, target);

    document.getElementById('btnStep').disabled = false;
    document.getElementById('btnStart').disabled = true;
    document.getElementById('resultBanner').className = 'result-banner';
    document.getElementById('resultBanner').textContent = '';
    document.getElementById('stepCounter').textContent = `Step 0 of ${steps.filter(s => !s.notFound).length}`;
    document.getElementById('logEntry').innerHTML = `Searching for <span class="hi val-c">${target}</span> in array of ${arr.length} elements. Press <strong>Step →</strong>.`;
    renderArray();
  }

  function stepSearch() {
    if (stepCount >= steps.length) return;
    const s = steps[stepCount];
    stepCount++;

    if (s.notFound) {
      renderArray({ lo: s.lo, hi: s.hi, mid: -1, found: false });
      document.getElementById('logEntry').innerHTML =
        `Search range exhausted. <span class="val-c">${target}</span> is <strong>not</strong> in the array.`;
      document.getElementById('stepCounter').textContent = `Done — ${steps.filter(x=>!x.notFound).length} iteration(s)`;
      showResult(false);
      finish();
      return;
    }

    renderArray(s);

    const midVal = arr[s.mid];
    const totalIter = steps.filter(x => !x.notFound).length;
    document.getElementById('stepCounter').textContent = `Step ${stepCount} of ${totalIter}`;

    let msg = `<span class="lo-c">lo=${s.lo}</span>, <span class="hi-c">hi=${s.hi}</span> → 
               mid = <span class="mid-c">${s.mid}</span>, arr[mid] = <span class="val-c">${midVal}</span>. `;

    if (s.found) {
      msg += `<span class="hi" style="color:#00e576">Found ${target} at index ${s.mid}!</span>`;
      document.getElementById('logEntry').innerHTML = msg;
      showResult(true, s.mid);
      finish();
    } else if (midVal < target) {
      msg += `${midVal} &lt; ${target} → search <strong>right half</strong>.`;
      document.getElementById('logEntry').innerHTML = msg;
    } else {
      msg += `${midVal} &gt; ${target} → search <strong>left half</strong>.`;
      document.getElementById('logEntry').innerHTML = msg;
    }

    if (stepCount >= steps.length) finish();
  }

  function showResult(found, idx) {
    const banner = document.getElementById('resultBanner');
    if (found) {
      banner.className = 'result-banner found-res';
      banner.textContent = `✔ Found ${target} at index ${idx}`;
    } else {
      banner.className = 'result-banner not-found-res';
      banner.textContent = `✖ ${target} is not in the array`;
    }
  }

  function finish() {
    document.getElementById('btnStep').disabled = true;
    done = true;
  }

  function resetAll() {
    document.getElementById('btnStep').disabled = true;
    document.getElementById('btnStart').disabled = false;
    document.getElementById('resultBanner').className = 'result-banner';
    document.getElementById('resultBanner').textContent = '';
    document.getElementById('stepCounter').textContent = 'Ready';
    document.getElementById('logEntry').innerHTML = 'Set a target value and press <strong>Start Search</strong> to begin.';
    steps = null; stepCount = 0; done = false;
    renderArray();
  }

  // Init
  document.getElementById('customArray').value = arr.join(', ');
  renderArray();

  // Allow Enter key on target input
  document.getElementById('targetInput').addEventListener('keydown', e => {
    if (e.key === 'Enter') {
      if (document.getElementById('btnStart').disabled === false) startSearch();
      else if (!document.getElementById('btnStep').disabled) stepSearch();
    }
  });
</script>
</body>
</html>
```

This gives you a proper interactive visualizer with:

- **Step-by-step control** — each click advances exactly one iteration, nothing jumps ahead
- **Live pointer labels** — LO, HI, and MID labels sit under their respective cells and move each step
- **Visual states** — mid element glows purple and scales up, found element glows green, eliminated halves shrink and fade, active range stays highlighted
- **Detailed log panel** — each step explains what was compared and which half is being searched next
- **Custom array input** — type your own sorted array with validation, or hit Random Array
- **Result banner** — clear found/not-found message with index when complete
- **Keyboard support** — Enter on the target field starts or steps the search

