        }

        @keyframes pulse {
            from { box-shadow: 0 0 12px rgba(76, 255, 145, 0.4); }
            to   { box-shadow: 0 0 28px rgba(76, 255, 145, 0.9); }
        }

        .legend {
            display: flex;
            gap: 20px;
            flex-wrap: wrap;
            justify-content: center;
            margin-bottom: 24px;
        }

        .legend-item {
