            align-items: center;
            gap: 7px;
            font-size: 0.82rem;
            color: #aaa;
        }

        .legend-box {
            width: 18px;
            height: 18px;
            border-radius: 4px;
            border: 2px solid;
        }

        .lb-range  { border-color: #4a90d9; background: #0d2340; }
        .lb-mid    { border-color: #f7c948; background: #2a1f00; }
        .lb-found  { border-color: #4cff91; background: #002a14; }
        .lb-elim   { border-color: #333;    background: #111; opacity: 0.4; }

        .info-panel {
            background: #1a1a2e;
            border: 1px solid #2a2a4a;
            border-radius: 14px;
            padding: 20px 28px;
            max-width: 600px;
            width: 100%;
            margin-bottom: 20px;
        }

        .info-panel h3 {
            color: #00d4ff;
            margin-bottom: 12px;
            font-size: 1rem;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .info-row {
            display: flex;
            justify-content: space-between;
            padding: 6px 0;
            border-bottom: 1px solid #1e1e3a;
            font-size: 0.92rem;
        }

        .info-row:last-child { border-bottom: none; }

        .info-label { color: #888; }
        .info-value { color: #fff; font-weight: 600; }
        .info-value.highlight { color: #f7c948; }

        .log-panel {
            background: #0d0d1a;
            border: 1px solid #2a2a4a;
            border-radius: 14px;
            padding: 16px 20px;
            max-width: 600px;
            width: 100%;
            max-height: 220px;
            overflow-y: auto;
        }

        .log-panel h3 {
            color: #7b2ff7;
            margin-bottom: 10px;
            font-size: 1rem;
            text-transform: uppercase;
