        }

        .result-banner.not-found {
            background: #2a0a0a;
            border: 2px solid #ff6b6b;
            color: #ff6b6b;
            display: block;
        }

        .pointer-row {
            display: flex;
            gap: 8px;
            flex-wrap: wrap;
            justify-content: center;
            margin-bottom: 6px;
            max-width: 900px;
            width: 100%;
            padding: 0 20px;
        }

        .pointer-cell {
            width: 56px;
            text-align: center;
            font-size: 0.7rem;
            font-weight: 700;
            height: 18px;
            line-height: 18px;
        }

        .ptr-low  { color: #4a90d9; }
        .ptr-mid  { color: #f7c948; }
        .ptr-high { color: #d94a4a; }
    </style>
</head>
<body>

<h1>Binary Search</h1>
<p class="subtitle">Step through the algorithm and watch it hunt your target</p>

<div class="controls">
    <label>Target:</label>
    <input type="number" id="targetInput" placeholder="e.g. 42" />
    <button id="startBtn" onclick="startSearch()">▶ Start</button>
    <button id="stepBtn" onclick="step()" disabled>⏭ Step</button>
    <button id="resetBtn" onclick="reset()">↺ Reset</button>
</div>

<div class="legend">
    <div class="legend-item"><div class="legend-box lb-range"></div> Search Range</div>
    <div class="legend-item"><div class="legend-box lb-mid"></div> Mid Element</div>
    <div class="legend-item"><div class="legend-box lb-found"></div> Found</div>
    <div class="legend-item"><div class="legend-box lb-elim"></div> Eliminated</div>
</div>

<div class="pointer-row" id="pointerRow"></div>
<div class="array-container" id="arrayContainer"></div>

<div class="result-banner" id="resultBanner"></div>

<div class="info-panel">
    <h3>Current State</h3>
    <div class="info-row">
        <span class="info-label">Low Index</span>
        <span class="info-value" id="infoLow">—</span>
    </div>
    <div class="info-row">
        <span class="info-label">High Index</span>
        <span class="info-value" id="infoHigh">—</span>
    </div>
    <div class="info-row">
        <span class="info-label">Mid Index</span>
        <span class="info-value highlight" id="infoMid">—</span>
    </div>
    <div class="info-row">
        <span class="info-label">Mid Value</span>
        <span class="info-value highlight" id="infoMidVal">—</span>
    </div>
    <div class="info-row">
        <span class="info-label">Target</span>
        <span class="info-value" id="infoTarget">—</span>
    </div>
    <div class="info-row">
        <span class="info-label">Iterations</span>
        <span class="info-value" id="infoIter">0</span>
    </div>
</div>

<div class="log-panel" id="logPanel">
    <h3>Step Log</h3>
    <div id="logEntries"></div>
</div>

<script>
    const DATA = [2, 5, 8, 12, 16, 23, 38, 45, 56, 72, 89, 94, 107, 120, 135];

    let low, high, mid, target, iteration, done, searchStarted;

    function buildArray() {
        const container = document.getElementById('arrayContainer');
        const pointerRow = document.getElementById('pointerRow');
        container.innerHTML = '';
        pointerRow.innerHTML = '';

        DATA.forEach((val, i) => {
            const wrapper = document.createElement('div');
            wrapper.className = 'cell-wrapper';

            const cell = document.createElement('div');
            cell.className = 'cell';
            cell.id = `cell-${i}`;
            cell.textContent = val;

            const idx = document.createElement('div');
            idx.className = 'cell-index';
            idx.textContent = i;

            wrapper.appendChild(cell);
            wrapper.appendChild(idx);
            container.appendChild(wrapper);

            const ptr = document.createElement('div');
            ptr.className = 'pointer-cell';
            ptr.id = `ptr-${i}`;
            pointerRow.appendChild(ptr);
        });
    }

    function updatePointers() {
        DATA.forEach((_, i) => {
            const ptr = document.getElementById(`ptr-${i}`);
            const labels = [];
            if (i === low)  labels.push('<span class="ptr-low">L</span>');
            if (i === mid)  labels.push('<span class="ptr-mid">M</span>');
            if (i === high) labels.push('<span class="ptr-high">H</span>');
            ptr.innerHTML = labels.join('');
        });
    }

    function updateCells() {
        DATA.forEach((_, i) => {
            const cell = document.getElementById(`cell-${i}`);
            cell.className = 'cell';
            if (done === 'found' && i === mid) {
                cell.classList.add('found');
            } else if (done === 'not-found') {
                cell.classList.add('eliminated');
            } else if (i < low || i > high) {
                cell.classList.add('eliminated');
            } else if (i === mid) {
                cell.classList.add('mid');
            } else {
                cell.classList.add('in-range');
            }
        });
    }

    function addLog(text, type = '') {
        const entries = document.getElementById('logEntries');
        const entry = document.createElement('div');
        entry.className = `log-entry ${type}`;
        entry.innerHTML = `<span class="step-num">#${iteration}</span><span class="log-text">${text}</span>`;
        entries.appendChild(entry);
        entries.scrollTop = entries.scrollHeight;
    }

    function updateInfo() {
        document.getElementById('infoLow').textContent    = done === 'not-found' ? '—' : low;
        document.getElementById('infoHigh').textContent   = done === 'not-found' ? '—' : high;
        document.getElementById('infoMid').textContent    = (mid !== undefined && mid !== null) ? mid : '—';
        document.getElementById('infoMidVal').textContent = (mid !== undefined && mid !== null) ? DATA[mid] : '—';
        document.getElementById('infoTarget').textContent = target;
        document.getElementById('infoIter').textContent   = iteration;
    }

    function startSearch() {
        const val = parseInt(document.getElementById('targetInput').value);
        if (isNaN(val)) {
            alert('Please enter a valid number!');
            return;
        }

        target = val;
        low = 0;
        high = DATA.length - 1;
        mid = null;
        iteration = 0;
        done = null;
        searchStarted = true;

        document.getElementById('resultBanner').className = 'result-banner';
        document.getElementById('resultBanner').style.display = 'none';
        document.getElementById('logEntries').innerHTML = '';

        buildArray();
        updateCells();
        updatePointers();
        updateInfo();

        document.getElementById('stepBtn').disabled = false;
        document.getElementById('startBtn').disabled = true;

        addLog(`Search started. Array has ${DATA.length} elements. Target = ${target}`, '');
    }

    function step() {
        if (done) return;

        if (low > high) {
            done = 'not-found';
            iteration++;
            updateCells();
            updatePointers();
            updateInfo();
            document.getElementById('stepBtn').disabled = true;
            document.getElementById('startBtn').disabled = false;
            const banner = document.getElementById('resultBanner');
            banner.className = 'result-banner not-found';
            banner.textContent = `✗ Target ${target} not found in the array.`;
            addLog(`Low (${low}) > High (${high}). Target ${target} not found!`, 'failure');
            return;
        }

        iteration++;
        mid = Math.floor((low + high) / 2);

        updateCells();
        updatePointers();
        updateInfo();

        if (DATA[mid] === target) {
            done = 'found';
            updateCells();
            document.getElementById('stepBtn').disabled = true;
            document.getElementById('startBtn').disabled = false;
            const banner = document.getElementById('resultBanner');
            banner.className = 'result-banner found';
            banner.textContent = `✓ Found ${target} at index ${mid} in ${iteration} iteration${iteration > 1 ? 's' : ''}!`;
            addLog(`Mid index = ${mid}, value = ${DATA[mid]}. ✓ FOUND at index ${mid}!`, 'success');
        } else if (DATA[mid] < target) {
            addLog(`Mid index = ${mid}, value = ${DATA[mid]} < ${target}. Search RIGHT half → low = ${mid + 1}`, '');
            low = mid + 1;
        } else {
            addLog(`Mid index = ${mid}, value = ${DATA[mid]} > ${target}. Search LEFT half → high = ${mid - 1}`, '');
            high = mid - 1;
        }
    }

    function reset() {
        done = null;
        searchStarted = false;
        mid = null;
        document.getElementById('targetInput').value = '';
        document.getElementById('resultBanner').className = 'result-banner';
        document.getElementById('resultBanner').style.display = 'none';
        document.getElementById('logEntries').innerHTML = '';
        document.getElementById('stepBtn').disabled = true;
        document.getElementById('startBtn').disabled = false;
        document.getElementById('infoLow').textContent    = '—';
        document.getElementById('infoHigh').textContent   = '—';
        document.getElementById('infoMid').textContent    = '—';
        document.getElementById('infoMidVal').textContent = '—';
        document.getElementById('infoTarget').textContent = '—';
        document.getElementById('infoIter').textContent   = '0';
        buildArray();
        document.getElementById('pointerRow').innerHTML = '';
        DATA.forEach(() => {
            const ptr = document.createElement('div');
            ptr.className = 'pointer-cell';
            document.getElementById('pointerRow').appendChild(ptr);
        });
    }

    // Keyboard shortcut: Enter to step
    document.addEventListener('keydown', e => {
        if (e.key === 'Enter' && searchStarted && !done) step();
    });

    buildArray();
</script>
</body>
</html>
```

## What it does:

- **15-element sorted array** rendered as numbered boxes with index labels beneath each
- **L / M / H pointer labels** float above the array showing Low, Mid, High positions each step
- **Color-coded states** — blue for active range, gold+glow for mid element, green pulse for found, dimmed for eliminated
- **Step button** (or press **Enter**) advances one iteration at a time
- **Info panel** shows exact Low/High/Mid indices and values live
- **Step log** records every decision with the comparison reasoning
- **Result banner** announces found (with index + iteration count) or not found
- Handles targets **in the array**, **not in the array**, and **edge cases** (first/last element)

