<script>
    const DATA = [2, 5, 8, 12, 16, 23, 38, 45, 56, 72, 89, 95, 103, 118, 134];

    let low, high, mid, target, stepNum, done, foundIndex;

    function buildArray() {
        const container = document.getElementById('arrayContainer');
        container.innerHTML = '';
        DATA.forEach((val, i) => {
            const box = document.createElement('div');
            box.className = 'box';
            box.id = `box-${i}`;
            box.innerHTML = `<span class="index-label">${i}</span>${val}`;
            container.appendChild(box);
        });
    }

    function clearBoxClasses() {
        DATA.forEach((_, i) => {
            const box = document.getElementById(`box-${i}`);
            box.className = 'box';
        });
    }

    function renderState() {
        clearBoxClasses();
        DATA.forEach((_, i) => {
            const box = document.getElementById(`box-${i}`);
            if (i < low || i > high) {
                box.classList.add('eliminated');
            } else {
                box.classList.add('in-range');
            }
        });

        if (!done) {
            const midBox = document.getElementById(`box-${mid}`);
            midBox.classList.remove('in-range');
            midBox.classList.add('mid', 'mid-marker');

            const lowBox = document.getElementById(`box-${low}`);
            const highBox = document.getElementById(`box-${high}`);
            lowBox.classList.add('low-marker');
            highBox.classList.add('high-marker');
        }

        if (foundIndex !== -1 && done) {
            clearBoxClasses();
            DATA.forEach((_, i) => {
                const box = document.getElementById(`box-${i}`);
                if (i === foundIndex) {
                    box.classList.add('found', 'mid-marker');
                } else {
                    box.classList.add('eliminated');
                }
            });
        }
    }

    function updateInfoPanel(message, extra) {
        const panel = document.getElementById('infoPanel');
        let html = `
            <div class="info-row"><span class="info-label">Target:</span><span class="info-value">${target}</span></div>
            <div class="info-row"><span class="info-label">Low index:</span><span class="info-value">${low} (value: ${DATA[low]})</span></div>
            <div class="info-row"><span class="info-label">High index:</span><span class="info-value">${high} (value: ${DATA[high]})</span></div>
            <div class="info-row"><span class="info-label">Mid index:</span><span class="info-value">${mid} (value: ${DATA[mid]})</span></div>
            <div class="info-row step-counter">Step ${stepNum}: ${message}</div>
        `;
        if (extra) {
            html += `<div class="result-banner ${foundIndex !== -1 ? 'found-result' : 'not-found-result'}">${extra}</div>`;
        }
        panel.innerHTML = html;
    }

    function addLog(msg) {
        const log = document.getElementById('logPanel');
        const entry = document.createElement('div');
        entry.className = 'log-entry';
        entry.innerHTML = msg;
        log.appendChild(entry);
        log.scrollTop = log.scrollHeight;
    }

    function startSearch() {
        const val = parseInt(document.getElementById('targetInput').value);
        if (isNaN(val)) {
            alert('Please enter a valid number.');
            return;
        }

        target = val;
        low = 0;
        high = DATA.length - 1;
        stepNum = 0;
        done = false;
        foundIndex = -1;

        document.getElementById('logPanel').innerHTML = '';
        document.getElementById('stepBtn').disabled = false;

        mid = Math.floor((low + high) / 2);
        renderState();

        const panel = document.getElementById('infoPanel');
        panel.innerHTML = `
            <div class="info-row"><span class="info-label">Target:</span><span class="info-value">${target}</span></div>
            <div class="info-row"><span class="info-label">Low index:</span><span class="info-value">${low} (value: ${DATA[low]})</span></div>
            <div class="info-row"><span class="info-label">High index:</span><span class="info-value">${high} (value: ${DATA[high]})</span></div>
            <div class="info-row"><span class="info-label">Mid index:</span><span class="info-value">${mid} (value: ${DATA[mid]})</span></div>
            <div class="info-row step-counter">Ready — click Step to begin.</div>
        `;

        addLog(`🔍 Searching for <span>${target}</span> in array of ${DATA.length} elements.`);
        addLog(`Initial: Low=<span>${low}</span>, High=<span>${high}</span>, Mid=<span>${mid}</span> (value: <span>${DATA[mid]}</span>)`);
    }

    function step() {
        if (done) return;

        stepNum++;

        if (low > high) {
            done = true;
            foundIndex = -1;
            renderState();
            updateInfoPanel('Search complete.', `❌ ${target} NOT FOUND in the array.`);
            addLog(`❌ Low > High — search exhausted. <span>${target}</span> not found.`);
            document.getElementById('stepBtn').disabled = true;
            return;
        }

        mid = Math.floor((low + high) / 2);
        const midVal = DATA[mid];

        if (midVal === target) {
            done = true;
            foundIndex = mid;
            renderState();
            updateInfoPanel(`DATA[${mid}] = ${midVal} = target!`, `✅ Found ${target} at index ${mid}!`);
            addLog(`✅ Step ${stepNum}: DATA[<span>${mid}</span>] = <span>${midVal}</span> = target! Found at index <span>${mid}</span>.`);
            document.getElementById('stepBtn').disabled = true;
        } else if (midVal < target) {
            renderState();
            updateInfoPanel(`DATA[${mid}]=${midVal} < ${target} → search RIGHT half`);
            addLog(`Step ${stepNum}: DATA[<span>${mid}</span>]=<span>${midVal}</span> < <span>${target}</span> → move Low to <span>${mid + 1}</span>`);
            low = mid + 1;
            if (low <= high) {
                mid = Math.floor((low + high) / 2);
                renderState();
            }
        } else {
            renderState();
            updateInfoPanel(`DATA[${mid}]=${midVal} > ${target} → search LEFT half`);
            addLog(`Step ${stepNum}: DATA[<span>${mid}</span>]=<span>${midVal}</span> > <span>${target}</span> → move High to <span>${mid - 1}</span>`);
            high = mid - 1;
            if (low <= high) {
                mid = Math.floor((low + high) / 2);
                renderState();
            }
        }

        if (!done && low > high) {
            setTimeout(() => step(), 0);
        }
    }

    function reset() {
        done = false;
        foundIndex = -1;
        stepNum = 0;
        document.getElementById('stepBtn').disabled = true;
        document.getElementById('targetInput').value = '';
        document.getElementById('logPanel').innerHTML = '';
        document.getElementById('infoPanel').innerHTML = '<div style="color:#555; font-size:0.9rem;">Enter a target value and click Start to begin.</div>';
        buildArray();
    }

    buildArray();
</script>
</body>
</html>
```

Here's what you get — no fluff:

- **15-element sorted array** displayed as numbered boxes with index labels
- **L / H / MID markers** rendered beneath and above boxes each step
- **Color states**: in-range (purple), mid (cyan glow + scale), found (green glow), eliminated (faded out)
- **Step button** walks through each iteration one click at a time
- **Info panel** shows current Low, High, Mid values and decision logic per step
- **Scrollable log** records every decision made during the search
- **Found / Not Found banner** with distinct styling when search concludes

Try targets like `23` (found), `56` (found), or `99` (not found) to see all paths.
